const items = $input.all();

const uniqueUrls = new Set();

items.forEach(item => {
  const channelUrl = item.json["YouTube Channel URL"];
  if (channelUrl && channelUrl.trim() !== "") {
    uniqueUrls.add(channelUrl.trim());
  }
});

const channelsArray = Array.from(uniqueUrls);


return [{
  json: {
    channels: channelsArray
  }
}];

const WCRSD_items = $('Whale Channel Reply System Data').all();
const MLD_items = $input.all();

const WCRSD_channels = WCRSD_items.map(item => item.json['YouTube Channel URL']).filter(url => url);

const MLD_channels_set = new Set(
  MLD_items.map(item => item.json['YouTube Channel URL']).filter(url => url)
);

const newChannels = WCRSD_channels.filter(url => !MLD_channels_set.has(url));

const uniqueNewChannels = [...new Set(newChannels)];

const channelsWithIds = uniqueNewChannels.map(url => {
  const channelId = url.split('/').pop(); 
  return {
    url: url,
    channelId: channelId
  };
});

return [{
  json: {
    channels: channelsWithIds,
    channelIds: channelsWithIds.map(ch => ch.channelId),
    channelUrls: uniqueNewChannels,
    totalWCRSD: WCRSD_channels.length,
    totalMLD: MLD_channels_set.size,
    newChannelsFound: uniqueNewChannels.length
  }
}];

const items = $input.all();

const results = items
  .filter(item => {
    return item.json.items && item.json.items.length > 0;
  })
  .map(item => {
    const channelData = item.json.items[0];
    const uploadsPlaylistId = channelData.contentDetails.relatedPlaylists.uploads;

    return {
      json: {
        channelId: channelData.id,
        channelTitle: channelData.snippet.title,
        channelDescription: channelData.snippet.description,

        uploadsPlaylistId: uploadsPlaylistId
      }
    };
  });

return results;

const items = $input.all();

const uploadPlaylistItems = $('Upload Playlists').all();

const results = items.map((item, index) => {
  const channelInfo = uploadPlaylistItems[index].json;

  const latestVideo = item.json.items[0].snippet;

  return {
    json: {
      channelId: channelInfo.channelId,
      channelTitle: channelInfo.channelTitle,
      channelDescription: channelInfo.channelDescription,

      latestVideoTitle: latestVideo.title,
      latestVideoDescription: latestVideo.description,
      latestVideoPublishedAt: latestVideo.publishedAt,
      videoId: latestVideo.resourceId.videoId,
      videoUrl: `https://www.youtube.com/watch?v=${latestVideo.resourceId.videoId}`
    }
  };
});

return results;

let aiResponse;
try {
  const inputData = $input.first().json;

  if (inputData.output && Array.isArray(inputData.output)) {
    // Your actual structure: output[0].content[0].text
    const firstOutput = inputData.output[0];
    if (firstOutput && firstOutput.content && firstOutput.content[0] && firstOutput.content[0].text) {
      aiResponse = firstOutput.content[0].text;
    } else {
      throw new Error('output array exists but missing content[0].text');
    }
  } else if (inputData.content && inputData.content.parts && inputData.content.parts[0]) {
    aiResponse = inputData.content.parts[0].text;
  } else if (inputData.message && inputData.message.content && inputData.message.content[0]) {
    aiResponse = inputData.message.content[0].text;
  } else if (inputData.text) {
    aiResponse = inputData.text;
  } else if (typeof inputData === 'string') {
    aiResponse = inputData;
  } else {
    return [{
      json: {
        error: true,
        message: 'Unknown AI response structure',
        rawResponse: JSON.stringify(inputData, null, 2)
      }
    }];
  }
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Error accessing AI response: ${error.message}`,
      rawInput: JSON.stringify($input.first().json, null, 2)
    }
  }];
}

let parsedData;
try {
  let cleanedResponse = aiResponse.trim();

  if (cleanedResponse.startsWith('```json')) {
    cleanedResponse = cleanedResponse.replace(/^```json\n?/, '').replace(/\n?```$/, '');
  } else if (cleanedResponse.startsWith('```')) {
    cleanedResponse = cleanedResponse.replace(/^```\n?/, '').replace(/\n?```$/, '');
  }

  parsedData = JSON.parse(cleanedResponse);
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Failed to parse JSON: ${error.message}`,
      rawResponse: aiResponse
    }
  }];
}

if (!Array.isArray(parsedData)) {
  return [{
    json: {
      error: true,
      message: 'AI response is not an array',
      parsedData: parsedData
    }
  }];
}

const results = parsedData.map((item) => {
  const channelId = item['Channel ID'] || 'ERROR: Missing Channel ID';
  return {
    json: {
      "YouTube Channel URL": `https://www.youtube.com/channel/${channelId}`,
      "Channel ID": channelId,
      "Niche": item['Niche'] || 'ERROR: Missing Niche',
      "Generated Message": item['Generated Message'] || 'ERROR: Missing Message',
      "Subject": item['Subject'] || 'ERROR: Missing Subject'
    }
  };
});

return results;
